    const [characters, setCharacters] = useState([])
    const [data, isLoading, isError] = useRequestData("https://hp-api.onrender.com/api/characters")
    console.log(data)



    return (
        <HomePageContainer>

            {characters.map((character) => {
                <div>
                    {console.log(character.actor)}
                    <CharacterCard nome={character.name} imagem={character.image} ator={character.actor}/>
                </div>
            })}


        </HomePageContainer>
    )
}
